def _deep_merge(old_value, new_value):
    if isinstance(old_value, dict) and isinstance(new_value, dict):
        merged = dict(old_value)
        for key, value in new_value.items():
            merged[key] = Features._deep_merge(merged[key], value) if key in merged else value
        return merged
    elif (
        isinstance(old_value, Sequence)
        and isinstance(new_value, Sequence)
        and isinstance(old_value.feature, dict)
        and isinstance(new_value.feature, dict)
    ):
        return Sequence(
            feature=Features._deep_merge(old_value.feature, new_value.feature),
            length=new_value.length,
            id=new_value.id,
